import{_ as l,o as i,c as t,ae as e}from"./chunks/framework.EHGTsUvI.js";const p=JSON.parse('{"title":"AI 基础设施与基座：MaaS、私有化部署与推理引擎怎么选","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/infrastructure.md","filePath":"ai-tutorial/infrastructure.md"}'),r={name:"ai-tutorial/infrastructure.md"};function o(d,a,h,s,n,u){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="ai-基础设施与基座-maas、私有化部署与推理引擎怎么选" tabindex="-1">AI 基础设施与基座：MaaS、私有化部署与推理引擎怎么选 <a class="header-anchor" href="#ai-基础设施与基座-maas、私有化部署与推理引擎怎么选" aria-label="Permalink to &quot;AI 基础设施与基座：MaaS、私有化部署与推理引擎怎么选&quot;">​</a></h1><blockquote><p>企业一旦认真准备把大模型接入业务，最先爆发争论的地方往往不是 Prompt，而是路线：继续调外部 API，还是把模型搬进自己机房？<br> 这场争论之所以总是吵得很凶，不是因为哪一边更“先进”，而是因为每条路线背后其实都捆着一整串现实代价：吞吐、成本、合规、弹性、运维、团队能力，少看哪一项，后面都会补课。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>MaaS 与私有化部署的主要取舍</li><li>为什么推理引擎是模型服务化的关键环节</li><li>团队在选基础设施时最容易忽视哪些成本</li></ul></div><h2 id="_1-两条常见路线-调用现成服务-或自己托管模型" tabindex="-1">1. 两条常见路线：调用现成服务，或自己托管模型 <a class="header-anchor" href="#_1-两条常见路线-调用现成服务-或自己托管模型" aria-label="Permalink to &quot;1. 两条常见路线：调用现成服务，或自己托管模型&quot;">​</a></h2><h3 id="_1-1-maas-model-as-a-service" tabindex="-1">1.1 MaaS（Model-as-a-Service） <a class="header-anchor" href="#_1-1-maas-model-as-a-service" aria-label="Permalink to &quot;1.1 MaaS（Model-as-a-Service）&quot;">​</a></h3><p>优点：</p><ul><li>上线快</li><li>模型能力更新快</li><li>运维负担低</li></ul><p>问题：</p><ul><li>成本随调用量增长</li><li>可控性受限</li><li>数据与合规边界需要额外评估</li></ul><h3 id="_1-2-私有化或自托管" tabindex="-1">1.2 私有化或自托管 <a class="header-anchor" href="#_1-2-私有化或自托管" aria-label="Permalink to &quot;1.2 私有化或自托管&quot;">​</a></h3><p>优点：</p><ul><li>数据边界更可控</li><li>能做更细的系统定制</li><li>对高吞吐、稳定业务可能更有成本优势</li></ul><p>问题：</p><ul><li>基础设施投入高</li><li>需要模型、推理、调度与运维能力</li><li>版本升级和容量规划复杂</li></ul><h2 id="_2-推理层为什么不是-把模型拉起来-这么简单" tabindex="-1">2. 推理层为什么不是“把模型拉起来”这么简单 <a class="header-anchor" href="#_2-推理层为什么不是-把模型拉起来-这么简单" aria-label="Permalink to &quot;2. 推理层为什么不是“把模型拉起来”这么简单&quot;">​</a></h2><p>很多团队第一次尝试私有化时，会直接用基础框架把模型跑起来。这适合验证，但不适合生产。</p><p>生产系统还要解决：</p><ul><li>并发调度</li><li>显存管理</li><li>请求批处理</li><li>流式输出</li><li>监控与故障恢复</li></ul><p>所以真正可用的“模型服务”通常不仅是模型本身，而是“模型 + 推理引擎 + 调度系统”。</p><h2 id="_3-一个更实用的基础设施判断框架" tabindex="-1">3. 一个更实用的基础设施判断框架 <a class="header-anchor" href="#_3-一个更实用的基础设施判断框架" aria-label="Permalink to &quot;3. 一个更实用的基础设施判断框架&quot;">​</a></h2><p>你可以从四个维度判断该走哪条路：</p><table tabindex="0"><thead><tr><th>维度</th><th>更偏 MaaS</th><th>更偏私有化</th></tr></thead><tbody><tr><td>启动速度</td><td>高</td><td>中低</td></tr><tr><td>合规与数据边界</td><td>中</td><td>高</td></tr><tr><td>运维复杂度</td><td>低</td><td>高</td></tr><tr><td>可定制性</td><td>中</td><td>高</td></tr></tbody></table><p>这不是谁绝对更好，而是看你的组织目标和阶段。</p><h2 id="_4-推理引擎的重要性" tabindex="-1">4. 推理引擎的重要性 <a class="header-anchor" href="#_4-推理引擎的重要性" aria-label="Permalink to &quot;4. 推理引擎的重要性&quot;">​</a></h2><p>一旦走自托管，推理引擎就成了关键。它决定：</p><ul><li>单机吞吐</li><li>显存利用率</li><li>多请求调度效率</li><li>流式体验</li></ul><p>很多现代推理引擎之所以重要，是因为它们能更好地处理：</p><ul><li>批处理</li><li>动态调度</li><li>KV Cache 管理</li><li>资源复用</li></ul><p>这部分能力直接影响成本和稳定性。</p><h2 id="_5-常见误区" tabindex="-1">5. 常见误区 <a class="header-anchor" href="#_5-常见误区" aria-label="Permalink to &quot;5. 常见误区&quot;">​</a></h2><h3 id="_5-1-只比较模型-不比较服务成本" tabindex="-1">5.1 只比较模型，不比较服务成本 <a class="header-anchor" href="#_5-1-只比较模型-不比较服务成本" aria-label="Permalink to &quot;5.1 只比较模型，不比较服务成本&quot;">​</a></h3><p>模型本体只是基础设施的一部分，真正长期影响成本的还包括：</p><ul><li>GPU 利用率</li><li>并发调度效率</li><li>监控与运维</li><li>故障处理流程</li></ul><h3 id="_5-2-只看单次响应-不看高峰吞吐" tabindex="-1">5.2 只看单次响应，不看高峰吞吐 <a class="header-anchor" href="#_5-2-只看单次响应-不看高峰吞吐" aria-label="Permalink to &quot;5.2 只看单次响应，不看高峰吞吐&quot;">​</a></h3><p>很多系统在低并发时看起来都不错，一到峰值就暴露问题。</p><h3 id="_5-3-低估组织能力门槛" tabindex="-1">5.3 低估组织能力门槛 <a class="header-anchor" href="#_5-3-低估组织能力门槛" aria-label="Permalink to &quot;5.3 低估组织能力门槛&quot;">​</a></h3><p>自托管不仅是“买卡”，还意味着你要承担模型服务化和稳定性建设。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>AI 基础设施的核心问题，从来不是“选哪个模型”这么单一，而是如何在：</p><ul><li>速度</li><li>成本</li><li>合规</li><li>稳定性</li><li>可定制性</li></ul><p>之间做持续平衡。理解这一点，后续讨论 RAG、Agent 和应用落地时，很多工程判断才会更有依据。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://docs.vllm.ai/" target="_blank" rel="noreferrer">vLLM 文档</a></li><li><a href="https://huggingface.co/docs/transformers/index" target="_blank" rel="noreferrer">Hugging Face Transformers</a></li><li>延伸阅读：<a href="./llm-apis.html">拥抱 AI Native：接入 API 指南</a></li></ul>',43)])])}const _=l(r,[["render",o]]);export{p as __pageData,_ as default};
